import './App.css';
import {Routes, Route} from 'react-router-dom'
import {routes} from './routes/routes'
import Section from './pages/section/Section';

function App() {
  return (
  <div className='App'>

      <Section />
    <Routes>
      {routes.map((route, index) => (
        <Route 
        key={index}
        path={route.path}
        element={route.element}
        />
      ))}
    </Routes>
  </div>
  );
}

export default App;
